const body = $input.first().json.body;
const entry    = body?.entry?.[0];
const change   = entry?.changes?.[0];
const value    = change?.value;
const messages = value?.messages;
if (!messages || messages.length === 0) { console.log('[wa-repuestos] Status update ignorado'); return []; }
const msg     = messages[0];
const contact = value?.contacts?.[0];
const meta    = value?.metadata;
return [{ json: {
  wa_message_id:        msg.id,
  message_type:         msg.type,
  message_text:         msg.type === 'text' ? msg.text?.body : null,
  timestamp_unix:       msg.timestamp,
  received_at:          new Date(parseInt(msg.timestamp) * 1000).toISOString(),
  from_phone:           msg.from,
  contact_name:         contact?.profile?.name || msg.from,
  phone_number_id:      meta?.phone_number_id,
  display_phone_number: meta?.display_phone_number
} }];

// ════════════════════════════════════════════════════════════════════════════
// FIND OR CREATE CONVERSATION — v2
// Fix: cuando is_new_conversation=true, limpiar customer_type y tags de tipo
//      del contacto para que la nueva conversación arranque NEUTRAL en Lovable
// Pegar en el nodo "Find or Create Conversation" → campo "JavaScript Code"
// ════════════════════════════════════════════════════════════════════════════

const SUPABASE_URL = 'https://ybbfcffzvcnovdobjwmd.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InliYmZjZmZ6dmNub3Zkb2Jqd21kIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MjM3MTMwMCwiZXhwIjoyMDk3OTQ3MzAwfQ.ch4GY1JTLTNWJd22qdvtIKwU58pwdzRWt7BIvCeo-F4';
const H = { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' };

const contactId = $input.first().json.id;
const tenantId  = $input.first().json.tenant_id;
const channelId = $('Buscar Canal1').first().json.id;

const cfgResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/ai_configs?tenant_id=eq.${tenantId}&channel_id=eq.${channelId}&is_active=eq.true&select=handoff_timeout_hours&limit=1`,
  headers: H
});
const timeoutHours = cfgResp?.[0]?.handoff_timeout_hours ?? 24;

const existing = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/conversations?tenant_id=eq.${tenantId}&contact_id=eq.${contactId}&status=in.(open,assigned)&select=id,status,last_message_at,created_at&order=created_at.desc&limit=1`,
  headers: H
});

if (Array.isArray(existing) && existing.length > 0) {
  const conv = existing[0];
  if (conv.status === 'open') {
    return [{ json: { conversation_id: conv.id, conversation_status: 'open', is_new_conversation: false } }];
  }
  if (conv.status === 'assigned') {
    const lastMsg = new Date(conv.last_message_at || conv.created_at);
    const hoursElapsed = (Date.now() - lastMsg.getTime()) / (1000 * 60 * 60);
    if (hoursElapsed < timeoutHours) {
      return [{ json: { conversation_id: conv.id, conversation_status: 'assigned', is_new_conversation: false } }];
    }
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/conversations?id=eq.${conv.id}`,
      headers: { ...H, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ status: 'resolved', resolved_at: new Date().toISOString() })
    });
  }
}

// ── Nueva conversación: crear y limpiar estado del contacto ──────────────────
const created = await this.helpers.httpRequest({
  method: 'POST',
  url: `${SUPABASE_URL}/rest/v1/conversations`,
  headers: { ...H, 'Prefer': 'return=representation' },
  body: JSON.stringify({ tenant_id: tenantId, contact_id: contactId, channel_type: 'whatsapp', status: 'open' })
});
const conversationId = created[0].id;

// FIX: limpiar customer_type y tags de tipo del contacto para que
// Lovable no muestre el tipo de cliente de la conversación anterior
try {
  const contactResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/contacts?id=eq.${contactId}&select=metadata,tags&limit=1`,
    headers: H
  });
  const contact = contactResp?.[0];
  if (contact) {
    const oldMeta = contact.metadata || {};
    const newMeta = { ...oldMeta };
    delete newMeta.customer_type;       // limpiar tipo de cliente (retail/wholesale)
    delete newMeta.pending_quote_items; // limpiar items de cotización pendientes

    // Tags de tipo de cliente a remover al inicio de nueva conversación
    const TYPE_TAGS = ['wholesale', 'retail', 'capiello', 'dipa', 'listo-para-cerrar'];
    const oldTags = contact.tags || [];
    const newTags = oldTags.filter(t => !TYPE_TAGS.includes(t));

    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/contacts?id=eq.${contactId}`,
      headers: { ...H, 'Prefer': 'return=minimal' },
      body: JSON.stringify({ metadata: newMeta, tags: newTags })
    });
    console.log('[NEW CONV] estado del contacto limpiado:', {
      removedCustomerType: oldMeta.customer_type || null,
      removedPendingItems: (oldMeta.pending_quote_items || []).length,
      removedTypeTags: oldTags.filter(t => TYPE_TAGS.includes(t))
    });
  }
} catch(e) {
  console.log('[NEW CONV] error limpiando estado del contacto (no crítico):', e.message);
}

return [{ json: { conversation_id: conversationId, conversation_status: 'open', is_new_conversation: true } }];

// ════════════════════════════════════════════════════════════════════════════
// PREPARAR_MENSAJES_OPENAI — v3
// Fix: cuando is_new_conversation=true, no usar customer_type guardado
//      de la sesión anterior → precio = default del canal (retail o wholesale)
// Pegar en el nodo "Preparar Mensajes OpenAI" → campo "JavaScript Code"
// ════════════════════════════════════════════════════════════════════════════

const historialItems = $input.all();
const canalData   = $('Buscar Canal1').first().json;
const tenantData  = $('Buscar Tenant').first().json;
const extractData = $('Extraer Datos WA').first().json;
const convData    = $('Find or Create Conversation').first().json;
const contactData = $('Upsert Contact').first().json;

const SUPABASE_URL = 'https://ybbfcffzvcnovdobjwmd.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InliYmZjZmZ6dmNub3Zkb2Jqd21kIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MjM3MTMwMCwiZXhwIjoyMDk3OTQ3MzAwfQ.ch4GY1JTLTNWJd22qdvtIKwU58pwdzRWt7BIvCeo-F4';
const H = { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` };

const channelId          = canalData.id;
const tenantId           = tenantData.id;
const channelSlug        = canalData.channel_slug || '';
const waAccessToken      = canalData.credentials?.access_token || '';
const channelPriceType   = canalData.config?.price_type || 'retail';
const contactMeta        = contactData.metadata || {};
const isNewConversation  = convData.is_new_conversation || false;

// FIX v3: si es conversación nueva, ignorar customer_type almacenado
// (puede ser de la sesión anterior). Cada conversación arranca con el
// precio por defecto del canal, hasta que CLASSIFY_CUSTOMER lo actualice.
const storedCustomerType = (!isNewConversation && contactMeta.customer_type) ? contactMeta.customer_type : null;
const effectivePriceType = storedCustomerType || channelPriceType;

// pending_quote_items: también ignorar si es conversación nueva
// (Find or Create Conversation v2 ya los borra en Supabase, pero
// Upsert Contact leyó la metadata ANTES de esa limpieza)
const pendingQuoteItems = isNewConversation ? [] : (contactMeta.pending_quote_items || []);

const cfgResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/ai_configs?tenant_id=eq.${tenantId}&channel_id=eq.${channelId}&is_active=eq.true&select=system_prompt,model,max_tokens,temperature&limit=1`,
  headers: H
});
const cfg = (Array.isArray(cfgResp) && cfgResp.length > 0) ? cfgResp[0] : {};
const systemPrompt = cfg.system_prompt || `Sos un asistente de ventas de ${tenantData.name}. Respondé en español rioplatense.`;
const model       = cfg.model || 'gpt-4o';
const maxTokens   = cfg.max_tokens || 600;
const temperature = typeof cfg.temperature === 'number' ? cfg.temperature : 0.7;

const historial = historialItems
  .filter(i => i.json.content != null && i.json.content !== '')
  .slice(-25)
  .map(i => ({ role: i.json.role === 'user' ? 'user' : 'assistant', content: i.json.content }));

const rawPhone = extractData.from_phone || '';
const toPhone = (rawPhone.startsWith('549') && rawPhone.length === 13) ? '54' + rawPhone.slice(3) : rawPhone;

// Inyectar contexto de productos ya mostrados (solo en conversaciones en curso)
let finalSystemPrompt = systemPrompt;
if (pendingQuoteItems.length > 0) {
  const pendingList = pendingQuoteItems
    .map(p => `"${p.name}" (product_id: ${p.product_id}, precio: $${p.price})`)
    .join('; ');
  finalSystemPrompt +=
    `\n\n[ESTADO DE SESIÓN]: Ya le mostraste estos productos al cliente: ${pendingList}. ` +
    `Si el cliente confirma, selecciona uno, o usa frases como "dame ese", "sí", "quiero ese", ` +
    `"ese mismo", "el mismo", "bueno", "dale", "ok", "ese", "perfecto": ` +
    `NO ejecutés SEARCH_PRODUCTS. ` +
    `Si aún no preguntaste la cantidad, preguntala ahora. ` +
    `Si ya tenés producto y cantidad confirmados, emitís CREATE_QUOTE con el product_id y la cantidad. ` +
    `Solo buscá productos nuevos si el cliente pide explícitamente algo diferente a lo ya mostrado.`;
}

console.log(`[PREPARAR] is_new_conv: ${isNewConversation} | storedType: ${contactMeta.customer_type || 'none'} | effectivePrice: ${effectivePriceType}`);

return [{ json: {
  messages_for_openai: [{ role: 'system', content: finalSystemPrompt }, ...historial],
  to_phone: toPhone,
  phone_number_id: extractData.phone_number_id,
  conversation_id: convData.conversation_id,
  tenant_id: tenantId,
  channel_id: channelId,
  channel_slug: channelSlug,
  price_type: effectivePriceType,
  pending_quote_items: pendingQuoteItems,
  wa_access_token: waAccessToken,
  model,
  max_tokens: maxTokens,
  temperature
} }];

const openAIResp = $input.first().json;
const aiText = openAIResp.choices?.[0]?.message?.content;
if (!aiText) throw new Error('[Analizar Markers] OpenAI no devolvio contenido');
const prepData = $('Preparar Mensajes OpenAI').first().json;
function extractMarker(text, marker) {
  const tag = `[${marker}:`;
  const start = text.indexOf(tag);
  if (start === -1) return null;
  const jsonStart = start + tag.length;
  let depth = 0, i = jsonStart;
  while (i < text.length) {
    if (text[i] === '{') depth++;
    else if (text[i] === '}') { depth--; if (depth === 0) { try { return JSON.parse(text.substring(jsonStart, i + 1)); } catch(e) { return null; } } }
    i++;
  }
  return null;
}
function cleanMarkers(text) {
  return (text || '')
    .replace(/\[SEARCH_PRODUCTS:\{[\s\S]*?\}\]/g, '')
    .replace(/\[PRODUCTS_RESULT:[\s\S]*?\]/g, '')
    .replace(/\[GET_PRODUCT_LINK:\{[\s\S]*?\}\]/g, '')
    .replace(/\[PRODUCT_LINK_RESULT:[\s\S]*?\]/g, '')
    .replace(/\[CREATE_QUOTE:\{[\s\S]*?\}\]\}?\]/g, '')
    .replace(/\[ADD_TAGS:\{[\s\S]*?\}\]/g, '')
    .replace(/\[UPSERT_VEHICLE:\{[\s\S]*?\}\]/g, '')
    .replace(/\[CLASSIFY_CUSTOMER:\{[\s\S]*?\}\]/g, '')
    .replace(/\[CREATE_OPPORTUNITY:\{[\s\S]*?\}\]/g, '')
    .replace(/\[DERIVAR:[^\]]+\]/g, '')
    .trim();
}
const searchProductsData   = extractMarker(aiText, 'SEARCH_PRODUCTS');
const getProductLinkData   = extractMarker(aiText, 'GET_PRODUCT_LINK');
const createQuoteData      = extractMarker(aiText, 'CREATE_QUOTE');
const addTagsData          = extractMarker(aiText, 'ADD_TAGS');
const upsertVehicleData    = extractMarker(aiText, 'UPSERT_VEHICLE');
const classifyCustomerData = extractMarker(aiText, 'CLASSIFY_CUSTOMER');
const derivarMatch         = aiText.match(/\[DERIVAR:([^\]]+)\]/);
const cleanedText          = cleanMarkers(aiText);
return [{ json: {
  has_search_products: !!searchProductsData, search_products_data: searchProductsData,
  has_get_product_link: !!getProductLinkData, get_product_link_data: getProductLinkData,
  has_create_quote: !!createQuoteData, create_quote_data: createQuoteData,
  has_add_tags: !!addTagsData, add_tags_data: addTagsData,
  has_upsert_vehicle: !!upsertVehicleData, upsert_vehicle_data: upsertVehicleData,
  has_classify_customer: !!classifyCustomerData, classify_customer_data: classifyCustomerData,
  derivar_reason: derivarMatch ? derivarMatch[1].trim() : null,
  should_handoff: !!derivarMatch,
  raw_text: aiText, cleaned_text: cleanedText,
  message_to_send: cleanedText || 'En breve te ayudo.',
  conversation_id: prepData.conversation_id, to_phone: prepData.to_phone,
  phone_number_id: prepData.phone_number_id, tenant_id: prepData.tenant_id,
  channel_id: prepData.channel_id, channel_slug: prepData.channel_slug,
  price_type: prepData.price_type, pending_quote_items: prepData.pending_quote_items || [],
  suggested_products: prepData.suggested_products || [],
  wa_access_token: prepData.wa_access_token,
  model: prepData.model, max_tokens: prepData.max_tokens, temperature: prepData.temperature,
  messages_for_openai: prepData.messages_for_openai
} }];

const state = $input.first().json;
if (!state.has_search_products && !state.has_get_product_link) return [{ json: state }];

const SUPABASE_URL = 'https://ybbfcffzvcnovdobjwmd.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InliYmZjZmZ6dmNub3Zkb2Jqd21kIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MjM3MTMwMCwiZXhwIjoyMDk3OTQ3MzAwfQ.ch4GY1JTLTNWJd22qdvtIKwU58pwdzRWt7BIvCeo-F4';
const OPENAI_KEY   = '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';
const SB = { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' };

function stem(t) { return (t.length > 4 && t.endsWith('s')) ? t.slice(0, -1) : t; }

function matchesVehicle(attrs, vehicle) {
  const comps = attrs?.compatibilities;
  if (!comps || !Array.isArray(comps) || comps.length === 0) return true;
  return comps.some(c => {
    const marcaOk  = !vehicle.marca  || c.marca?.toLowerCase()  === vehicle.marca.toLowerCase();
    const modeloOk = !vehicle.modelo || c.modelo?.toLowerCase().includes(vehicle.modelo.toLowerCase());
    const anioOk   = !vehicle.año    || ((!c.año_desde || c.año_desde <= vehicle.año) && (!c.año_hasta || c.año_hasta >= vehicle.año));
    const motorOk  = !vehicle.motor  || !c.motor || c.motor?.toString().toLowerCase().includes(vehicle.motor.toString().toLowerCase());
    return marcaOk && modeloOk && anioOk && motorOk;
  });
}

function extractMarker(text, marker) {
  const tag = `[${marker}:`; const start = text.indexOf(tag); if (start === -1) return null;
  const jsonStart = start + tag.length; let depth = 0, i = jsonStart;
  while (i < text.length) {
    if (text[i] === '{') depth++;
    else if (text[i] === '}') { depth--; if (depth === 0) { try { return JSON.parse(text.substring(jsonStart, i + 1)); } catch(e) { return null; } } }
    i++;
  }
  return null;
}

function cleanMarkers(text) {
  return (text || '')
    .replace(/\[SEARCH_PRODUCTS:\{[\s\S]*?\}\]/g, '').replace(/\[PRODUCTS_RESULT:[\s\S]*?\]/g, '')
    .replace(/\[GET_PRODUCT_LINK:\{[\s\S]*?\}\]/g, '').replace(/\[PRODUCT_LINK_RESULT:[\s\S]*?\]/g, '')
    .replace(/\[CREATE_QUOTE:\{[\s\S]*?\}\]\}?\]/g, '').replace(/\[ADD_TAGS:\{[\s\S]*?\}\]/g, '')
    .replace(/\[UPSERT_VEHICLE:\{[\s\S]*?\}\]/g, '').replace(/\[CLASSIFY_CUSTOMER:\{[\s\S]*?\}\]/g, '')
    .replace(/\[CREATE_OPPORTUNITY:\{[\s\S]*?\}\]/g, '').replace(/\[DERIVAR:[^\]]+\]/g, '')
    .replace(/\[PRODUCTS_FALLBACK:[\s\S]*?\]/g, '')
    .trim();
}

let injectedBlocks = [];
let suggestedProducts = state.suggested_products || [];

if (state.has_search_products) {
  const filters   = state.search_products_data || {};
  const vehicle   = filters.vehicle || {};
  const priceType = state.price_type;

  const rawTerm = filters.keyword || filters.query || filters.category || null;
  const STOP    = new Set(['de','del','la','el','los','las','un','una','y','o','para','con','en','al','por']);
  const tokens  = rawTerm
    ? rawTerm.toLowerCase().split(/\s+/).filter(t => t.length > 2 && !STOP.has(t))
    : [];

  console.log('[SEARCH] rawTerm:', rawTerm, '| tokens:', tokens, '| tenant:', state.tenant_id);

  const seen = new Set();
  let allProducts = [];

  for (const token of tokens) {
    const enc = encodeURIComponent(token);
    try {
      const r = await this.helpers.httpRequest({ method: 'GET', headers: SB,
        url: `${SUPABASE_URL}/rest/v1/products?tenant_id=eq.${state.tenant_id}&is_available=eq.true&category=ilike.*${enc}*&select=id,name,sku,price,category,stock,attributes,metadata&order=name.asc&limit=60` });
      if (Array.isArray(r)) r.forEach(p => { if (!seen.has(p.id)) { seen.add(p.id); allProducts.push(p); } });
    } catch(e) { console.log('[SEARCH] cat error:', e.message); }
    try {
      const r = await this.helpers.httpRequest({ method: 'GET', headers: SB,
        url: `${SUPABASE_URL}/rest/v1/products?tenant_id=eq.${state.tenant_id}&is_available=eq.true&name=ilike.*${enc}*&select=id,name,sku,price,category,stock,attributes,metadata&order=name.asc&limit=60` });
      if (Array.isArray(r)) r.forEach(p => { if (!seen.has(p.id)) { seen.add(p.id); allProducts.push(p); } });
    } catch(e) { console.log('[SEARCH] name error:', e.message); }
  }

  console.log('[SEARCH] total antes de filtros:', allProducts.length);

  if (tokens.length > 1) {
    const stemmedTokens = tokens.map(stem);
    allProducts = allProducts.filter(p => {
      const text = ((p.name || '') + ' ' + (p.category || '')).toLowerCase();
      return stemmedTokens.every(st => text.includes(st));
    });
    console.log('[SEARCH] después de cross-filter:', allProducts.length);
  }

  const matched = allProducts.filter(p => matchesVehicle(p.attributes, vehicle)).slice(0, 5);
  console.log('[SEARCH] compatibles con vehículo:', matched.length);

  const toForAI = (products) => products.map(p => {
    const wp    = p.attributes?.wholesale_price;
    const price = (priceType === 'wholesale' && wp) ? wp : p.price;
    return { id: p.id, name: p.name, sku: p.sku, category: p.category, price,
             stock: p.stock, in_stock: p.stock === null || p.stock > 0,
             has_link: !!p.metadata?.ecommerce_url,
             compatibilities: (p.attributes?.compatibilities || []).slice(0, 2) };
  });

  if (matched.length > 0) {
    const forAI = toForAI(matched);
    injectedBlocks.push(`[PRODUCTS_RESULT:${JSON.stringify(forAI)}]`);
    suggestedProducts = forAI.map(p => ({ product_id: p.id, name: p.name, sku: p.sku, price: p.price, quantity: 1 }));
  } else if (allProducts.length > 0) {
    const fallbackForAI = toForAI(allProducts.slice(0, 3));
    injectedBlocks.push(`[PRODUCTS_RESULT:sin_compatibilidad_confirmada][PRODUCTS_FALLBACK:${JSON.stringify(fallbackForAI)}]`);
  } else {
    injectedBlocks.push('[PRODUCTS_RESULT:ninguno]');
  }
}

if (state.has_get_product_link) {
  const pid = state.get_product_link_data?.product_id;
  if (pid) {
    try {
      const prod = await this.helpers.httpRequest({ method: 'GET', headers: SB,
        url: `${SUPABASE_URL}/rest/v1/products?id=eq.${pid}&tenant_id=eq.${state.tenant_id}&select=name,sku,metadata&limit=1` });
      if (Array.isArray(prod) && prod.length > 0) {
        const link = prod[0].metadata?.ecommerce_url;
        injectedBlocks.push(link
          ? `[PRODUCT_LINK_RESULT:${JSON.stringify({ name: prod[0].name, sku: prod[0].sku, url: link })}]`
          : `[PRODUCT_LINK_RESULT:${JSON.stringify({ error: 'sin_link', name: prod[0].name })}]`);
      }
    } catch(e) { console.log('[LINK] error:', e.message); }
  }
}

if (injectedBlocks.length === 0) return [{ json: { ...state, suggested_products: suggestedProducts } }];

let finalText = state.raw_text;
try {
  const secondCall = await this.helpers.httpRequest({
    method: 'POST', url: 'https://api.openai.com/v1/chat/completions',
    headers: { 'Authorization': `Bearer ${OPENAI_KEY}`, 'Content-Type': 'application/json' },
    body: JSON.stringify({ model: state.model || 'gpt-4o',
      messages: [...state.messages_for_openai, { role: 'user', content: injectedBlocks.join('\n') }],
      max_tokens: state.max_tokens || 600, temperature: state.temperature || 0.7 })
  });
  finalText = secondCall.choices?.[0]?.message?.content || state.raw_text;
} catch(e) { console.log('[2a llamada] error:', e.message); }

const newCreateQuoteData   = extractMarker(finalText, 'CREATE_QUOTE')      || state.create_quote_data;
const newAddTagsData       = extractMarker(finalText, 'ADD_TAGS')          || state.add_tags_data;
const newUpsertVehicleData = extractMarker(finalText, 'UPSERT_VEHICLE')    || state.upsert_vehicle_data;
const newClassifyData      = extractMarker(finalText, 'CLASSIFY_CUSTOMER') || state.classify_customer_data;
const dm = finalText.match(/\[DERIVAR:([^\]]+)\]/) || (state.derivar_reason ? [null, state.derivar_reason] : null);
const cleanedFinal = cleanMarkers(finalText);

return [{ json: { ...state,
  raw_text: finalText, cleaned_text: cleanedFinal,
  message_to_send: cleanedFinal || state.message_to_send,
  suggested_products: suggestedProducts,
  has_search_products: false, has_get_product_link: false,
  has_create_quote: !!newCreateQuoteData, create_quote_data: newCreateQuoteData,
  has_add_tags: !!newAddTagsData, add_tags_data: newAddTagsData,
  has_upsert_vehicle: !!newUpsertVehicleData, upsert_vehicle_data: newUpsertVehicleData,
  has_classify_customer: !!newClassifyData, classify_customer_data: newClassifyData,
