// CREAR_COTIZACION1 — v2
// Fix: fallback funciona con múltiples pending_quote_items
//      usa el texto del resumen del bot para identificar producto y cantidad
// Pegar en el nodo "Crear Cotización1" → campo "JavaScript Code"
// ════════════════════════════════════════════════════════════════════════════

const state = $input.first().json;
const pendingQuoteItems = state.pending_quote_items || [];
const UUID_REGEX = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

// ── Fallback determinístico ────────────────────────────────────────────────
// Se activa cuando el AI emitió DERIVAR pero omitió CREATE_QUOTE,
// y el cliente había confirmado un resumen previo.
let effectiveQuoteData = state.create_quote_data || null;
let effectiveHasQuote  = state.has_create_quote  || false;

if (!effectiveHasQuote && pendingQuoteItems.length >= 1) {
  const msgs    = state.messages_for_openai || [];
  const lastUser = [...msgs].reverse().find(m => m.role === 'user');
  const lastBot  = [...msgs].reverse().find(m => m.role === 'assistant');

  const AFFIRM      = /\b(si|sí|dale|ok|va|listo|confirmo|confirmado|perfecto|bueno|claro|adelante|procede|procedo|cotiza|hacelo|sigan)\b/i;
  const ASK_CONFIRM = /resumen del pedido|cotizaci[oó]n|confirma|total.*\$|\$.*total|presupuesto|¿confirm/i;

  if (lastUser && AFFIRM.test(lastUser.content) && lastBot && ASK_CONFIRM.test(lastBot.content)) {
    let pi = pendingQuoteItems[0]; // fallback al primero

    // Si hay más de un ítem pendiente, intentar identificar cuál está en el resumen
    if (pendingQuoteItems.length > 1) {
      const resumeText = lastBot.content.toLowerCase();
      const matched = pendingQuoteItems.find(p =>
        resumeText.includes((p.name || '').toLowerCase().slice(0, 20))
      );
      if (matched) {
        pi = matched;
        console.log('[CREATE_QUOTE] producto identificado del resumen:', pi.name);
      } else {
        console.log('[CREATE_QUOTE] no pude identificar producto del resumen, usando primero:', pi.name);
      }
    }

    // Intentar extraer cantidad del resumen ("Cantidad: 6 unidades")
    const qtyMatch = lastBot.content.match(/Cantidad:\s*(\d+)/i);
    const qty = qtyMatch ? parseInt(qtyMatch[1]) : (pi.quantity || 1);

    effectiveQuoteData = {
      items: [{ product_id: pi.product_id, quantity: qty, notes: null }],
      notes: null
    };
    effectiveHasQuote = true;
    console.log('[CREATE_QUOTE] fallback activado — producto:', pi.product_id, '| qty:', qty);
  }
}

if (!effectiveHasQuote || !effectiveQuoteData) return [{ json: state }];

const SUPABASE_URL = 'https://ybbfcffzvcnovdobjwmd.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InliYmZjZmZ6dmNub3Zkb2Jqd21kIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MjM3MTMwMCwiZXhwIjoyMDk3OTQ3MzAwfQ.ch4GY1JTLTNWJd22qdvtIKwU58pwdzRWt7BIvCeo-F4';
const SB = { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Accept': 'application/json' };

const priceType = state.price_type;
const tenantId  = state.tenant_id;
const convId    = state.conversation_id;
const items     = effectiveQuoteData.items || [];
if (items.length === 0) return [{ json: state }];

const convResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/conversations?id=eq.${convId}&select=contact_id&limit=1`,
  headers: SB
});
const contactId = convResp?.[0]?.contact_id;
if (!contactId) return [{ json: state }];

const resolvedItems = [];
let totalAmount = 0;

for (const item of items) {
  let resolvedId = item.product_id;

  // UUID fallback si el AI mandó placeholder
  if (!resolvedId || !UUID_REGEX.test(resolvedId)) {
    const validPending = pendingQuoteItems.filter(p => UUID_REGEX.test(p.product_id));
    if (validPending.length === 1) {
      resolvedId = validPending[0].product_id;
      console.log('[CREATE_QUOTE] UUID sustituido desde pending (único válido):', resolvedId);
    } else if (validPending.length > 1) {
      resolvedId = validPending[0].product_id;
      console.log('[CREATE_QUOTE] UUID sustituido desde pending (primero de varios):', resolvedId);
    } else {
      console.log('[CREATE_QUOTE] product_id inválido sin fallback:', item.product_id);
      continue;
    }
  }

  const prodResp = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/products?id=eq.${resolvedId}&tenant_id=eq.${tenantId}&is_available=eq.true&select=id,name,sku,price,attributes&limit=1`,
    headers: SB
  });
  if (!Array.isArray(prodResp) || prodResp.length === 0) continue;

  const product   = prodResp[0];
  const qty       = Math.max(1, parseInt(item.quantity) || 1);
  const wp        = product.attributes?.wholesale_price;
  const unitPrice = (priceType === 'wholesale' && wp) ? Number(wp) : Number(product.price);
  if (!unitPrice || isNaN(unitPrice)) continue;

  const subtotal = unitPrice * qty;
  totalAmount += subtotal;
  resolvedItems.push({
    product_id: product.id, product_name: product.name, sku: product.sku || null,
    price_type: priceType, unit_price: unitPrice, quantity: qty, subtotal,
    notes: item.notes || null
  });
}

if (resolvedItems.length === 0) return [{ json: { ...state, quote_error: 'sin_items_validos' } }];

// Generar número de cotización
let quoteNumber = 'Q-00001';
try {
  const existing = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/quotes?tenant_id=eq.${tenantId}&select=quote_number&order=created_at.desc&limit=200`,
    headers: SB
  });
  if (Array.isArray(existing) && existing.length > 0) {
    const nums   = existing.map(q => q.quote_number).filter(n => /^Q-\d+$/.test(n)).map(n => parseInt(n.slice(2)));
    const maxNum = Math.max(...nums);
    const next   = isFinite(maxNum) ? maxNum + 1 : 1;
    quoteNumber  = 'Q-' + String(next).padStart(5, '0');
  }
} catch(e) { console.log('[QN] error:', e.message); }

// Crear cotización
const quoteResp = await this.helpers.httpRequest({
  method: 'POST',
  url: `${SUPABASE_URL}/rest/v1/quotes`,
  headers: { ...SB, 'Prefer': 'return=representation' },
  body: JSON.stringify({
    tenant_id: tenantId, contact_id: contactId, conversation_id: convId,
    channel_id: state.channel_id, quote_number: quoteNumber,
    price_type: priceType, status: 'sent',
    total_amount: totalAmount, currency: 'ARS',
    notes: effectiveQuoteData.notes || null
  })
});
const quoteId = quoteResp?.[0]?.id;
if (!quoteId) return [{ json: state }];

// Insertar ítems
for (const qi of resolvedItems) {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${SUPABASE_URL}/rest/v1/quote_items`,
    headers: { ...SB, 'Prefer': 'return=minimal' },
    body: JSON.stringify({ quote_id: quoteId, ...qi })
  });
}

const totalFmt = new Intl.NumberFormat('es-AR', { style: 'currency', currency: 'ARS', maximumFractionDigits: 0 }).format(totalAmount);
const quoteText = `\n\n📋 *Cotización ${quoteNumber}*\nTotal: ${totalFmt} (${priceType === 'wholesale' ? 'precio mayorista' : 'precio minorista'})`;

return [{ json: {
  ...state,
  quote_number: quoteNumber,
  quote_id: quoteId,
  quote_total: totalAmount,
  message_to_send: state.message_to_send + quoteText,
  has_create_quote: false
} }];

const state = $input.first().json;
const hasWork = state.has_add_tags || state.has_upsert_vehicle || state.has_classify_customer
               || (state.suggested_products?.length > 0) || !!state.quote_id;
if (!hasWork) return [{ json: state }];
const SUPABASE_URL = 'https://ybbfcffzvcnovdobjwmd.supabase.co';
const SUPABASE_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InliYmZjZmZ6dmNub3Zkb2Jqd21kIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc4MjM3MTMwMCwiZXhwIjoyMDk3OTQ3MzAwfQ.ch4GY1JTLTNWJd22qdvtIKwU58pwdzRWt7BIvCeo-F4';
const SB = { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json', 'Accept': 'application/json' };
const convResp = await this.helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/conversations?id=eq.${state.conversation_id}&select=contact_id&limit=1`, headers: SB });
const contactId = convResp?.[0]?.contact_id;
if (!contactId) return [{ json: state }];
const contactResp = await this.helpers.httpRequest({ method: 'GET', url: `${SUPABASE_URL}/rest/v1/contacts?id=eq.${contactId}&select=tags,metadata&limit=1`, headers: SB });
const contact     = contactResp?.[0] || {};
const currentTags = contact.tags || [];
const currentMeta = contact.metadata || {};
const patch = {};
// ── Tags: ADD_TAGS marker ─────────────────────────────────────────────
if (state.has_add_tags && state.add_tags_data?.tags) {
  const newTags = Array.isArray(state.add_tags_data.tags) ? state.add_tags_data.tags : [state.add_tags_data.tags];
  patch.tags = [...new Set([...currentTags, ...newTags])];
}
// ── Metadata ──────────────────────────────────────────────────────────
const metaPatch = { ...currentMeta };
if (state.has_upsert_vehicle && state.upsert_vehicle_data) {
  metaPatch.vehicle = { ...(currentMeta.vehicle || {}), ...state.upsert_vehicle_data };
}
if (state.has_classify_customer && state.classify_customer_data) {
  const cd = state.classify_customer_data;
  if (cd.customer_type) metaPatch.customer_type = cd.customer_type;
  if (cd.location)      metaPatch.location = cd.location;
  if (cd.company)       metaPatch.company  = cd.company;
  // Tags según tipo de cliente (sin pisar otras tags como listo-para-cerrar)
  let tags = [...(patch.tags || currentTags)];
  if (cd.customer_type === 'retail') {
    tags = tags.filter(t => !['wholesale', 'capiello'].includes(t));
    tags = [...new Set([...tags, 'retail', 'dipa'])];
  } else if (cd.customer_type === 'wholesale') {
    tags = tags.filter(t => !['retail', 'dipa'].includes(t));
    tags = [...new Set([...tags, 'wholesale', 'capiello'])];
  }
  patch.tags = tags;
}
// ── pending_quote_items ───────────────────────────────────────────────
if (state.quote_id) {
  delete metaPatch.pending_quote_items;
} else if (state.suggested_products?.length > 0) {
  metaPatch.pending_quote_items = state.suggested_products;
}
if (JSON.stringify(metaPatch) !== JSON.stringify(currentMeta)) patch.metadata = metaPatch;
if (Object.keys(patch).length > 0) {
  await this.helpers.httpRequest({ method: 'PATCH', url: `${SUPABASE_URL}/rest/v1/contacts?id=eq.${contactId}`, headers: { ...SB, 'Prefer': 'return=minimal' }, body: JSON.stringify(patch) });
}
return [{ json: state }];
